#include <Wire.h>
#include <MPU6050.h>
#include <OneWire.h>
#include <DallasTemperature.h>
#include <SPI.h>
#include <LoRa.h>
#include <SD.h>
#define MUX 0x70
#define N_IMU 3
#define BUZZER 8
#define LED 9
#define SD_CS 10
#define ONE_WIRE_BUS 2
#define FS_WARN 1.5f
#define FS_CRIT 1.2f
OneWire ow(ONE_WIRE_BUS); DallasTemperature ds(&ow);
MPU6050 imu;

float slope_factor_of_safety(float c,float g,float gw,float z,float b,float p){
  b*=PI/180;p*=PI/180;
  float num=c+(g-gw)*z*cos(b)*cos(b)*tan(p);
  float den=g*z*sin(b)*cos(b);
  return den>0?num/den:99;
}

void mux_sel(int ch){Wire.beginTransmission(MUX);Wire.write(1<<ch);Wire.endTransmission();}

float read_tilt(int ch){
  mux_sel(ch);imu.initialize();
  int16_t ax,ay,az,gx,gy,gz;
  imu.getMotion6(&ax,&ay,&az,&gx,&gy,&gz);
  return atan2((float)ax,(float)az)*180.0f/PI;
}

void send_lora(float*t,float fs,float T){
  LoRa.beginPacket();
  LoRa.print(fs);LoRa.print(',');
  for(int i=0;i<N_IMU;i++){LoRa.print(t[i]);LoRa.print(',');}
  LoRa.print(T);LoRa.endPacket();
}

void run_alarm(float fs){
  if(fs<FS_CRIT){tone(BUZZER,2500);analogWrite(LED,255);}
  else if(fs<FS_WARN){tone(BUZZER,1000);analogWrite(LED,128);}
  else{noTone(BUZZER);analogWrite(LED,0);}
}

void log_sd(float*t,float fs){
  File f=SD.open("slope.csv",FILE_WRITE);
  if(f){f.print(millis());f.print(',');f.print(fs);for(int i=0;i<N_IMU;i++){f.print(',');f.print(t[i]);}f.println();f.close();}
}

void setup(){Wire.begin();Serial.begin(115200);ds.begin();LoRa.begin(915E6);SD.begin(SD_CS);pinMode(BUZZER,OUTPUT);pinMode(LED,OUTPUT);}

void loop(){
  float t[N_IMU];
  for(int i=0;i<N_IMU;i++) t[i]=read_tilt(i);
  float beta=t[0];
  float fs=slope_factor_of_safety(5.0f,18.0f,9.81f,1.5f,beta,30.0f);
  ds.requestTemperatures();float T=ds.getTempCByIndex(0);
  run_alarm(fs);log_sd(t,fs);send_lora(t,fs,T);
  Serial.print("FS=");Serial.println(fs);
  delay(60000);
}
